                            <label className="block text-sm font-medium text-gray-700 mb-1">دسته‌بندی</label>
                            <select value={category} onChange={e => setCategory(e.target.value)} className="w-full rounded-lg border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500">
                                <option>تک لایه</option>
                                <option>سه لایه</option>
                                <option>پنج لایه</option>
                                <option>اتصالات</option>
                                <option>شیرآلات</option>
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">تصویر محصول</label>
                            <input type="file" accept="image/*" onChange={handleImageChange} className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100 cursor-pointer" />
                            {imagePreview && <img src={imagePreview} alt="Preview" className="mt-2 h-16 w-16 object-contain border rounded-lg" />}
                        </div>
                        <div className="md:col-span-2">
                            <label className="block text-sm font-medium text-gray-700 mb-1">قابلیت مشاهده</label>
                            <div className="flex flex-wrap items-center gap-6 mt-2">
                                <label className="flex items-center cursor-pointer">
                                    <input type="radio" name="visibility-type" value="public" checked={type === 'public'} onChange={() => setType('public')} className="h-4 w-4 text-blue-600 focus:ring-blue-500" />
                                    <span className="ml-2 text-sm text-gray-700">همه مشتریان</span>
                                </label>
                                <label className="flex items-center cursor-pointer">
                                    <input type="radio" name="visibility-type" value="specific" checked={type === 'specific'} onChange={() => setType('specific')} className="h-4 w-4 text-blue-600 focus:ring-blue-500" />
                                    <span className="ml-2 text-sm text-gray-700">مشتریان خاص</span>
                                </label>
                            </div>
                            {type === 'specific' && (
                                <div className="relative mt-3">
                                    <button type="button" onClick={() => setIsCustomerDropdownOpen(!isCustomerDropdownOpen)} className="w-full text-right bg-gray-50 border border-gray-300 rounded-lg py-2 px-3 flex justify-between items-center text-sm">
                                        <span>{selectedCustomerIds.length > 0 ? `${selectedCustomerIds.length} مشتری انتخاب شده` : 'انتخاب مشتریان...'}</span>
                                        <svg xmlns="http://www.w3.org/2000/svg" className={`h-4 w-4 transition-transform ${isCustomerDropdownOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                                    </button>
                                    {isCustomerDropdownOpen && (
                                        <div className="absolute z-10 mt-1 w-full bg-white shadow-lg border rounded-lg max-h-60 overflow-auto p-1">
                                            {customers.map(customer => (
                                                <div key={customer.id} className="flex items-center p-2 hover:bg-gray-100 rounded cursor-pointer" onClick={() => handleCustomerSelection(customer.id)}>
                                                    <input type="checkbox" checked={selectedCustomerIds.includes(customer.id)} onChange={() => {}} className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                                                    <label className="ml-3 flex-1 text-sm text-gray-700 cursor-pointer">{customer.name} <span className="text-gray-400 text-xs">({customer.company})</span></label>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Sizes Table for NEW product */}
                <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-100">
                    <div className="flex justify-between items-center border-b pb-4 mb-6">
                        <h2 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                            <span className="bg-gray-800 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">۲</span>
                            سایزها و قیمت‌های کالای جدید
                        </h2>
                        <button type="button" onClick={addVariantRow} className="text-blue-600 hover:text-blue-700 text-sm font-semibold flex items-center gap-1">
                            <PlusIcon /> افزودن ردیف
                        </button>
                    </div>
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm text-right">
                            <thead className="bg-gray-50 text-gray-600 font-semibold border-b border-gray-200">
                                <tr>
                                    <th className="px-4 py-3">سایز</th>
                                    <th className="px-4 py-3">کد کالا</th>
                                    <th className="px-4 py-3">قیمت (ریال)</th>
                                    <th className="px-4 py-3 text-center">بسته</th>
                                    <th className="px-4 py-3 text-center">کارتن</th>
                                    <th className="px-4 py-3">وضعیت</th>
                                    <th className="px-4 py-3 w-10"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {variants.map((variant) => (
                                    <tr key={variant.id}>
                                        <td className="px-2 py-2"><input type="text" value={variant.size} onChange={(e) => handleVariantChange(variant.id, 'size', e.target.value)} className="w-full border-gray-300 rounded-md text-sm" /></td>
                                        <td className="px-2 py-2"><input type="text" value={variant.code} onChange={(e) => handleVariantChange(variant.id, 'code', e.target.value)} className="w-full border-gray-300 rounded-md text-sm" /></td>
                                        <td className="px-2 py-2"><input type="number" value={variant.price} onChange={(e) => handleVariantChange(variant.id, 'price', e.target.value)} className="w-full border-gray-300 rounded-md text-sm" /></td>
                                        <td className="px-2 py-2"><input type="number" value={variant.packageQuantity} onChange={(e) => handleVariantChange(variant.id, 'packageQuantity', e.target.value)} className="w-full border-gray-300 rounded-md text-sm text-center" /></td>
                                        <td className="px-2 py-2"><input type="number" value={variant.cartonQuantity} onChange={(e) => handleVariantChange(variant.id, 'cartonQuantity', e.target.value)} className="w-full border-gray-300 rounded-md text-sm text-center" /></td>
                                        <td className="px-2 py-2">
                                            <select value={variant.stock} onChange={(e) => handleVariantChange(variant.id, 'stock', e.target.value)} className="w-full border-gray-300 rounded-md text-sm">
                                                <option>موجود</option>
                                                <option>ناموجود</option>
                                                <option>تعداد محدود</option>
                                            </select>
                                        </td>
                                        <td className="px-2 py-2 text-center">
                                            {variants.length > 1 && <button type="button" onClick={() => removeVariantRow(variant.id)} className="text-gray-400 hover:text-red-500"><TrashIcon /></button>}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>

                <div className="flex justify-end">
                    <button type="submit" className="bg-green-600 text-white font-bold px-8 py-3 rounded-lg hover:bg-green-700 shadow-md transition-colors flex items-center gap-2 text-lg">
                        <PlusIcon /> ثبت نهایی کالای جدید
                    </button>
                </div>
            </form>

            {/* List of Existing Products with Inline Editing */}
            <div className="mt-12 bg-white p-6 rounded-lg shadow-sm border border-gray-200">
                <h2 className="text-lg font-bold text-gray-800 border-b pb-4 mb-4">لیست محصولات و ویرایش سریع</h2>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-right text-gray-600">
                        <thead className="bg-gray-50 text-gray-700 uppercase font-semibold">
                            <tr>
                                <th className="px-4 py-3 w-16 text-center">تصویر</th>
                                <th className="px-4 py-3">نام و کد</th>
                                <th className="px-4 py-3">دسته‌بندی</th>
                                <th className="px-4 py-3 text-center">بسته</th>
                                <th className="px-4 py-3 text-center">کارتن</th>
                                <th className="px-4 py-3">قیمت</th>
                                <th className="px-4 py-3">نمایش برای</th>
                                <th className="px-4 py-3 text-center">عملیات</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200">
                            {products.length > 0 ? products.map((product, index) => (
                                <tr key={product.code + index} className="hover:bg-gray-50 transition-colors">
                                    <td className="px-4 py-4 text-center">
                                        <img src={product.imageUrl} alt={product.name} className="h-10 w-10 object-contain bg-gray-100 rounded p-1 mx-auto" />
                                    </td>
                                    <td className="px-4 py-4">
                                        <p className="font-bold text-gray-800">{product.name}</p>
                                        <p className="text-xs text-gray-500 font-mono">{product.code}</p>
                                    </td>
                                    <td className="px-4 py-4">
                                        <span className="bg-gray-100 px-2 py-1 rounded text-xs">{product.category}</span>
                                    </td>
                                    <td className="px-4 py-4 text-center">
                                        <input 
                                            type="number" 
                                            value={product.packageQuantity} 
                                            onChange={(e) => handleInlineUpdate(product.code, 'packageQuantity', e.target.value)}
                                            className="w-16 text-center border-gray-200 rounded-md text-xs focus:ring-blue-500" 
                                        />
                                    </td>
                                    <td className="px-4 py-4 text-center">
                                        <input 
                                            type="number" 
                                            value={product.cartonQuantity} 
                                            onChange={(e) => handleInlineUpdate(product.code, 'cartonQuantity', e.target.value)}
                                            className="w-16 text-center border-gray-200 rounded-md text-xs focus:ring-blue-500" 
                                        />
                                    </td>
                                    <td className="px-4 py-4">
                                        <input 
                                            type="text" 
                                            value={product.price} 
                                            onChange={(e) => handleInlineUpdate(product.code, 'price', e.target.value)}
                                            className="w-28 text-right border-gray-200 rounded-md text-xs font-semibold focus:ring-blue-500" 
                                        />
                                    </td>
                                    <td className="px-4 py-4">
                                        <select 
                                            value={product.type || 'public'} 
                                            onChange={(e) => handleInlineUpdate(product.code, 'type', e.target.value)}
                                            className="border-gray-200 rounded-md text-xs focus:ring-blue-500"
                                        >
                                            <option value="public">عمومی</option>
                                            <option value="specific">اختصاصی</option>
                                        </select>
                                    </td>
                                    <td className="px-4 py-4 text-center">
                                        <div className="flex items-center justify-center gap-1">
                                            <button 
                                                onClick={() => handleSaveChanges(product)} 
                                                className="p-2 text-green-600 hover:bg-green-50 rounded-full transition-colors"
                                                title="ذخیره تغییرات"
                                            >
                                                <div className="scale-75"><CheckIcon /></div>
                                            </button>
                                            <button 
                                                onClick={() => handleDeleteProduct(product.code)} 
                                                className="p-2 text-red-500 hover:bg-red-50 rounded-full transition-colors" 
                                                title="حذف"
                                            >
                                                <TrashIcon />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan={8} className="px-6 py-12 text-center text-gray-500 italic">هیچ محصولی در لیست وجود ندارد.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default ProductManagement;

