                        <MenuIcon className={`h-6 w-6 ${isScrolled ? 'text-gray-900' : 'text-white'}`} />
                    </button>
                </div>
            </div>

            {/* Mobile Menu Overlay */}
            {isMobileMenuOpen && (
                <div className="fixed inset-0 bg-[#004696] z-[200] flex flex-col p-8">
                    <div className="flex justify-between items-center mb-12">
                        <div className="text-2xl font-black text-white italic">FPI.</div>
                        <button onClick={() => setIsMobileMenuOpen(false)} className="text-white">
                            <CloseIcon />
                        </button>
                    </div>
                    <nav className="flex flex-col gap-6">
                        {navLinks.map((link) => (
                            <a 
                                key={link.title} 
                                href={link.href}
                                className="text-2xl font-bold text-white hover:text-blue-300 transition-colors border-b border-white/10 pb-4"
                                onClick={() => setIsMobileMenuOpen(false)}
                            >
                                {link.title}
                            </a>
                        ))}
                        <button 
                            onClick={() => { onNavigateToLogin(); setIsMobileMenuOpen(false); }}
                            className="mt-8 bg-white text-[#004696] font-black py-4 rounded-xl text-center"
                        >
                            ورود به پنل مشتریان
                        </button>
                    </nav>
                </div>
            )}
        </header>
    );
};

